// Solution class
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
int findFirstDuplicate(int A[], int n) {
    unordered_set<int> seen;
    for (int i = 0; i < n; i++) {
        if (seen.find(A[i]) != seen.end()) return i;
        seen.insert(A[i]);
    }
    return -1;
}};

