// Solution class
public class Solution {
public int findFirstDuplicate(int A[], int n) {
    HashSet<Integer> seen = new HashSet<>();
    for (int i = 0; i < n; i++) {
        if (seen.contains(A[i])) return i;
        seen.add(A[i]);
    }
    return -1;
}};

